	var finalizeHold time.Duration
	for _, sample := range samples {
		if sample.Section == "land_post_land_finalize" {
			finalizeHold = sample.Hold
		}
	}
	if finalizeHold == 0 {
		t.Fatal("did not capture land_post_land_finalize lock sample")
